package io.arex.inst.dubbo.apache.v3;
import org.apache.dubbo.rpc.*;
public class DubboProviderExtractor extends io.arex.inst.dubbo.common.DubboExtractor {
    public static void onServiceEnter(Invoker<?> invoker, Invocation invocation) {
        io.arex.inst.runtime.listener.CaseEventDispatcher.onEvent(io.arex.inst.runtime.listener.CaseEvent.ofEnterEvent());
        io.arex.inst.dubbo.apache.v3.DubboAdapter adapter = io.arex.inst.dubbo.apache.v3.DubboAdapter.of(invoker, invocation);
        if (io.arex.inst.dubbo.common.DubboExtractor.shouldSkip(adapter)) {
            return;
        }
        java.lang.String caseId = adapter.getCaseId();
        java.lang.String excludeMockTemplate = adapter.getExcludeMockTemplate();
        io.arex.inst.runtime.listener.CaseEventDispatcher.onEvent(io.arex.inst.runtime.listener.CaseEvent.ofCreateEvent(io.arex.inst.runtime.listener.EventSource.of(caseId, excludeMockTemplate)));
    }

    public static void onServiceExit(Invoker<?> invoker, Invocation invocation, Result result) {
        if (!io.arex.inst.runtime.context.ContextManager.needRecordOrReplay()) {
            return;
        }
        io.arex.inst.dubbo.common.DubboExtractor.setResponseHeader((k, v) -> io.arex.inst.dubbo.apache.v3.DubboProviderExtractor.setAttachment(invocation, k, v));
        io.arex.inst.dubbo.apache.v3.DubboAdapter adapter = io.arex.inst.dubbo.apache.v3.DubboAdapter.of(invoker, invocation);
